proof fn phi_1_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.implies(q).satisfied_by(ex),
        p.satisfied_by(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_2_spec_entails_tla_forall_bridge(spec: TempPred<int>, a_to_p: spec_fn(int) -> TempPred<int>)
    requires
        forall |a: int| spec.entails(#[trigger] a_to_p(a)),
    ensures
        spec.entails(tla_forall(a_to_p)),
{
    spec_entails_tla_forall::<int, int>(spec, a_to_p);
}
